"use strict";

(function () {
	function onReady(callback) {
		if (document.readyState === "loading") {
			document.addEventListener("DOMContentLoaded", callback);
			return;
		}
		callback();
	}

	function getActionFromNode(node) {
		if (!node) {
			return "";
		}
		if (node.dataset && node.dataset.action) {
			return node.dataset.action;
		}
		return node.getAttribute("data-action") || "";
	}

	onReady(function () {
		var calendarRoot = document.getElementById("tui-calendar-init");
		if (!calendarRoot) {
			return;
		}

		var cal = window.cal || null;
		if (!cal && window.tui && typeof window.tui.Calendar === "function") {
			var fallbackCalendars = Array.isArray(window.CalendarList) && window.CalendarList.length
				? window.CalendarList
				: [{
					id: "1",
					name: "Calendar",
					color: "#ffffff",
					bgColor: "#2563eb",
					borderColor: "#2563eb"
				}];

			cal = new window.tui.Calendar("#tui-calendar-init", {
				defaultView: "month",
				useCreationPopup: false,
				useDetailPopup: true,
				calendars: fallbackCalendars
			});
			window.cal = cal;

			if (Array.isArray(window.ScheduleList) && window.ScheduleList.length && typeof cal.createSchedules === "function") {
				cal.createSchedules(window.ScheduleList);
			}
		}

		if (!cal) {
			return;
		}

		function updateCalendarTypeLabel() {
			var nameEl = document.getElementById("calendarTypeName");
			var iconEl = document.getElementById("calendarTypeIcon");
			if (!nameEl || !iconEl || typeof cal.getViewName !== "function") {
				return;
			}

			var viewName = cal.getViewName();
			var options = typeof cal.getOptions === "function" ? cal.getOptions() : {};
			var visibleWeeks = options && options.month ? options.month.visibleWeeksCount : 0;
			var label = "Monthly";
			var iconClass = "calendar-icon feather feather-grid fs-12 me-1";

			if (viewName === "day") {
				label = "Daily";
				iconClass = "calendar-icon feather feather-list fs-12 me-1";
			} else if (viewName === "week") {
				label = "Weekly";
				iconClass = "calendar-icon feather feather-umbrella fs-12 me-1";
			} else if (visibleWeeks === 2) {
				label = "2 weeks";
				iconClass = "calendar-icon feather feather-sliders fs-12 me-1";
			} else if (visibleWeeks === 3) {
				label = "3 weeks";
				iconClass = "calendar-icon feather feather-framer fs-12 me-1";
			}

			nameEl.textContent = label;
			iconEl.className = iconClass;
		}

		function updateRenderRange() {
			var rangeEl = document.getElementById("renderRange");
			if (!rangeEl || typeof cal.getDateRangeStart !== "function" || typeof cal.getDateRangeEnd !== "function") {
				return;
			}

			var start = cal.getDateRangeStart();
			var end = cal.getDateRangeEnd();
			var viewName = typeof cal.getViewName === "function" ? cal.getViewName() : "month";
			var monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
			var text = "";

			if (viewName === "day") {
				text = monthNames[start.getMonth()] + " " + start.getDate() + ", " + start.getFullYear();
			} else if (viewName === "month") {
				text = monthNames[start.getMonth()] + " " + start.getFullYear();
			} else {
				text = monthNames[start.getMonth()] + " " + start.getDate() + " - " + monthNames[end.getMonth()] + " " + end.getDate();
			}

			rangeEl.textContent = text;
		}

		function refreshSchedules() {
			if (typeof window.generateSchedule === "function" && Array.isArray(window.ScheduleList) && typeof cal.clear === "function" && typeof cal.createSchedules === "function") {
				cal.clear();
				window.generateSchedule(cal.getViewName(), cal.getDateRangeStart(), cal.getDateRangeEnd());
				cal.createSchedules(window.ScheduleList);
				return;
			}

			if (typeof cal.render === "function") {
				cal.render(true);
			}
		}

		function applyAction(action, sourceEl) {
			if (!action) {
				return;
			}

			if (action === "move-prev") {
				if (typeof cal.prev === "function") {
					cal.prev();
				}
				refreshSchedules();
				updateRenderRange();
				return;
			}

			if (action === "move-next") {
				if (typeof cal.next === "function") {
					cal.next();
				}
				refreshSchedules();
				updateRenderRange();
				return;
			}

			if (action === "move-today") {
				if (typeof cal.today === "function") {
					cal.today();
				}
				refreshSchedules();
				updateRenderRange();
				return;
			}

			if (typeof cal.getOptions !== "function" || typeof cal.setOptions !== "function" || typeof cal.changeView !== "function") {
				return;
			}

			var options = cal.getOptions();
			var viewName = "";
			var checkbox = sourceEl ? sourceEl.querySelector("input[type='checkbox']") : null;

			switch (action) {
				case "toggle-daily":
					viewName = "day";
					break;
				case "toggle-weekly":
					viewName = "week";
					break;
				case "toggle-monthly":
					options.month.visibleWeeksCount = 0;
					viewName = "month";
					break;
				case "toggle-weeks2":
					options.month.visibleWeeksCount = 2;
					viewName = "month";
					break;
				case "toggle-weeks3":
					options.month.visibleWeeksCount = 3;
					viewName = "month";
					break;
				case "toggle-narrow-weekend":
					options.month.narrowWeekend = !options.month.narrowWeekend;
					options.week.narrowWeekend = options.month.narrowWeekend;
					viewName = cal.getViewName();
					if (checkbox) {
						checkbox.checked = !!options.month.narrowWeekend;
					}
					break;
				case "toggle-start-day-1":
					options.month.startDayOfWeek = options.month.startDayOfWeek ? 0 : 1;
					options.week.startDayOfWeek = options.month.startDayOfWeek;
					viewName = cal.getViewName();
					if (checkbox) {
						checkbox.checked = !!options.month.startDayOfWeek;
					}
					break;
				case "toggle-workweek":
					options.month.workweek = !options.month.workweek;
					options.week.workweek = options.month.workweek;
					viewName = cal.getViewName();
					if (checkbox) {
						checkbox.checked = !options.month.workweek;
					}
					break;
				default:
					return;
			}

			cal.setOptions(options, true);
			cal.changeView(viewName || cal.getViewName(), true);
			updateCalendarTypeLabel();
			updateRenderRange();
			refreshSchedules();
		}

		document.addEventListener("click", function (event) {
			var actionEl = event.target.closest("[data-action]");
			if (!actionEl) {
				return;
			}

			var action = getActionFromNode(actionEl);
			if (!action) {
				return;
			}

			var inCalendarControl = actionEl.closest("#menu") || actionEl.closest(".menu-navi") || actionEl.closest(".move-day") || actionEl.closest(".move-today");
			if (!inCalendarControl) {
				return;
			}

			event.preventDefault();
			applyAction(action, actionEl.closest("[role='menuitem']") || actionEl);
		});

		document.addEventListener("change", function (event) {
			var target = event.target;
			if (!target || !target.classList || !target.classList.contains("chalendar-checkbox")) {
				return;
			}

			var action = target.value || getActionFromNode(target.closest("[data-action]"));
			if (!action) {
				return;
			}

			applyAction(action, target.closest("[role='menuitem']") || target.parentElement);
		});

		updateCalendarTypeLabel();
		updateRenderRange();
	});
})();